// Serve intelligence products to Telegram: latest edition, recent history,
// or an organisation/date search. Registry-agnostic: the command maps to a
// product archive directory under /reports/archive/<id> (mounted). Reading the
// directory requires the n8n env NODE_FUNCTION_ALLOW_BUILTIN=fs (set in
// docker-compose). Fails safe: if listing is unavailable, returns guidance.
const text = ($('Telegram Trigger').item.json.message.text || '').trim();
const cmd = text.split(/\s+/)[0].toLowerCase();
const query = text.split(/\s+/).slice(1).join(' ').toLowerCase();
const map = {
  '/opportunities': { id: 'cyber-opportunities', name: 'Cyber Opportunities Brief' },
  '/energy': { id: 'energy-intelligence', name: 'Energy Intelligence Brief' },
  '/cyber': { id: 'cyber-brief', name: 'Cyber Threat Brief' }
};
const p = map[cmd] || map['/opportunities'];
let reply;
try {
  const fs = require('fs');
  const dir = `/reports/archive/${p.id}`;
  let files = fs.readdirSync(dir).filter(f => f.endsWith('.html')).sort();
  if (query) files = files.filter(f => f.toLowerCase().includes(query));
  if (!files.length) {
    reply = `No ${p.name} editions found${query ? ` matching \"${query}\"` : ''} yet. Briefings are generated on schedule and emailed automatically.`;
  } else {
    const latest = files[files.length - 1];
    const recent = files.slice(-5).reverse().map(f => ` • ${f}`).join('\n');
    reply = `📰 ${p.name}\nLatest: ${latest}\nRecent editions:\n${recent}\n\nStored under reports/archive/${p.id}/. Reply with an org or date to search (e.g. \"${cmd} adnoc\").`;
  }
} catch (e) {
  reply = `📰 ${p.name}: the latest edition is delivered by email and stored under reports/archive/${p.id}/. (Live listing unavailable: ${e.message})`;
}
return [{ json: { reply } }];
